6	type ClaimStep = { op: "claim"; policy: number; incident: Incident };
7	type Step = QuoteStep | ClaimStep;
8	type Scenario = { customer: Customer; steps: Step[] };
9	type Policy = { items: Item[]; remainingCap: number };
