11	const PROCESSING_FEE = 5;
12	const DEDUCTIBLE = 100;
13	const CAP_MULTIPLIER = 2;
14	
15	const INSURANCE_VALUE: Record<string, number> = {
16	  sword: 1000,
17	  amulet: 600,
18	  staff: 800,
19	  potion: 400,
20	  rune: 250,
21	  moonstone: 250,
22	};
23	
24	const FIRST_INSURANCE_RATE = 0.1;
25	const CURSE_SURCHARGE_RATE = 0.5;
26	const HIGH_ENCHANTMENT_RATE = 0.3;
27	const HIGH_ENCHANTMENT_THRESHOLD = 5;
28	const LOYALTY_DISCOUNT_RATE = 0.2;
29	const LOYALTY_THRESHOLD_YEARS = 2;
30	const FOLLOWUP_DISCOUNT_RATE = 0.15;
31	
32	const COMPONENT_BLOCK_SIZE = 3;
33	const COMPONENT_BLOCK_PRICE = 60;
34	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
35	
36	const BASE_PREMIUM: Record<string, number> = {
37	  sword: 100,
38	  amulet: 60,
39	  staff: 80,
40	  potion: 40,
41	  rune: 25,
42	  moonstone: 25,
43	};
