45	const countByType = (items: Item[]): Record<string, number> => {
46	  const counts: Record<string, number> = {};
47	  for (const item of items) counts[item.type] = (counts[item.type] ?? 0) + 1;
48	  return counts;
49	};
50	
51	const qualifiesForComponentBlock = (type: string, count: number): boolean =>
52	  COMPONENT_TYPES.has(type) && count === COMPONENT_BLOCK_SIZE;
53	
54	const lineItemPrice = (type: string, count: number): number =>
55	  qualifiesForComponentBlock(type, count)
56	    ? COMPONENT_BLOCK_PRICE
57	    : BASE_PREMIUM[type] * count;
58	
59	const sumBasePremiums = (items: Item[]): number =>
60	  Object.entries(countByType(items))
61	    .reduce((total, [type, count]) => total + lineItemPrice(type, count), 0);
62	
63	const rateOf = (amount: number, rate: number, applies: boolean): number =>
64	  applies ? amount * rate : 0;
65	
66	const isCursed = (item: Item): boolean => item.cursed === true;
67	
68	const isHighlyEnchanted = (item: Item): boolean =>
69	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
70	
71	const itemSurcharges = (items: Item[]): number =>
72	  items.reduce((sum, item) => {
73	    const base = BASE_PREMIUM[item.type];
74	    return sum
75	      + rateOf(base, CURSE_SURCHARGE_RATE, isCursed(item))
76	      + rateOf(base, HIGH_ENCHANTMENT_RATE, isHighlyEnchanted(item));
77	  }, 0);
78	
79	const isLoyalCustomer = (customer: Customer): boolean =>
80	  customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS;
81	
82	const isFollowupContract = (stepIndex: number): boolean => stepIndex > 0;
83	
84	const quotePremium = (items: Item[], customer: Customer, stepIndex: number): number => {
85	  const basePremium = sumBasePremiums(items);
86	  const surcharges = itemSurcharges(items);
87	  const firstInsurance = basePremium * FIRST_INSURANCE_RATE;
88	  const loyaltyDiscount = rateOf(basePremium, LOYALTY_DISCOUNT_RATE, isLoyalCustomer(customer));
89	  const followupDiscount = rateOf(basePremium, FOLLOWUP_DISCOUNT_RATE, isFollowupContract(stepIndex));
90	  return Math.ceil(basePremium + surcharges + firstInsurance - loyaltyDiscount - followupDiscount + PROCESSING_FEE);
91	};
92	
93	const validateItems = (items: Item[]): void => {
94	  for (const item of items) {
95	    if (!(item.type in BASE_PREMIUM)) {
96	      throw new Error(`Unknown item type: ${item.type}`);
97	    }
98	  }
99	};
100	
101	const insuranceSum = (items: Item[]): number =>
102	  items.reduce((sum, item) => sum + INSURANCE_VALUE[item.type], 0);
103	
104	const processClaim = (policy: Policy, incident: Incident): { payout: number; remainingCap: number } => {
105	  const payout = incident.damages.reduce((sum, dmg) => sum + (dmg.amount - DEDUCTIBLE), 0);
106	  policy.remainingCap -= payout;
107	  return { payout, remainingCap: policy.remainingCap };
108	};
