const insuranceSum = (items: Item[]): number =>
  items.reduce((sum, item) => sum + INSURANCE_VALUE[item.type], 0);

const damagePayout = (damage: Damage): number => damage.amount - DEDUCTIBLE;

const totalPayout = (incident: Incident): number =>
  incident.damages.reduce((sum, dmg) => sum + damagePayout(dmg), 0);

const processClaim = (policy: Policy, incident: Incident): { payout: number; remainingCap: number } => {
  const payout = totalPayout(incident);
  policy.remainingCap -= payout;
  return { payout, remainingCap: policy.remainingCap };
};

